&lt;p&gt;Soit le code suivant. Combien de fois le composant va-t-il se re-rendre après le clic sur le bouton ?&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;
function Counter() {
  const [count, setCount] = useState(0);
  const handleClick = () =&gt; {
    setCount(1);
    setCount(2);
    setCount(3);
  };
  return &lt;Button onPress={handleClick} /&gt;;
}
&lt;/code&gt;&lt;/pre&gt;

&lt;p&gt;Que va afficher la console après l'exécution de ce code ?&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;
function App() {
  const [count, setCount] = useState(0);
  const handleClick = () =&gt; {
    setCount(count + 1);
    console.log(count);
  };
  return &lt;Button onPress={handleClick} title={count.toString()} /&gt;;
}
&lt;/code&gt;&lt;/pre&gt;

&lt;p&gt;Soit ce code. Quel est le problème et comment le corriger ?&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;
const [todos, setTodos] = useState([]);
const addTodo = () =&gt; {
  todos.push({ id: Date.now(), text: 'Nouvelle tâche' });
  setTodos(todos);
};
&lt;/code&gt;&lt;/pre&gt;
